                            Id = new Guid("bbbbbbbb-1111-1111-1111-111111111111"),
                            InInvestigatorsNotes = "Lady Eleanor uppträder kyligt och kontrollerat men reagerar starkt när frågor om familj och tidigare relationer nämns.",
                            MurderCaseId = new Guid("22222222-2222-2222-2222-222222222222"),
                            Name = "Lady Eleanor Whitmore",
                            Role = "Överklassdam",
                            Statement = "Förhörsrapport:\n\n\"Jag reste mot Edinburgh för att besöka min syster, hennes makes bortgång har tagit mycket hårt på henne\n\nJag sovit? Sitandes? Sånt gör inte en Whitmore. Jag på min höjd blundade lite. Jag blir så åksju i tåg.\n\nDen döde mannen? Nej, jag har aldrig tidigare sett honom.\n\nJag måste dock erkänna att jag fann det märkligt att en så enkelt klädd person reste i förstaklass.\n\nNär jag var ung hade människor betydligt bättre förståelse för sin plats i samhället.\"",
